#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long r1, r2, r3;
        scanf("%lld %lld %lld", &r1, &r2, &r3);
        if(r1 > r2 + r3 || r2 > r1 + r3 || r3 > r1 + r2)
            printf("YES\n");
        else
            printf("NO\n");
    }
    return 0;
}

